code = """import json
import os

# Get the full data
file_path = '/home/user/tmp/tmp_mongo_result_2dfbe8c8.json'

with open(file_path, 'r') as f:
    all_articles = json.load(f)

print('Total articles: ' + str(len(all_articles)))

# Sports keywords
def is_sports(article):
    text = (article['title'] + ' ' + article['description']).lower()
    keywords = ['sports','football','soccer','basketball','baseball','tennis','golf','race','racing','game','team','player','coach','match','athlete','championship','tournament','olympic','f1','grand prix','marathon']
    for kw in keywords:
        if kw in text:
            return True
    return False

# Find sports articles
sports = []
for article in all_articles:
    if is_sports(article):
        sports.append({
            'title': article['title'],
            'desc_len': len(article['description'])
        })

# Find longest
if sports:
    longest = max(sports, key=lambda x: x['desc_len'])
    answer = longest['title']
    print('Found ' + str(len(sports)) + ' sports articles')
    print('Longest: ' + answer + ' (' + str(longest['desc_len']) + ' chars)')
else:
    answer = 'No sports articles'
    print(answer)

print('__RESULT__:')
print(json.dumps(answer))"""

